mapper.select:
/* cetusApprovedDataset.getDatasetPage */ SELECT CAD.UID AS APPROVED_UID ,CAD.METADATA_ID ,TO_CHAR(CAD.APPROVED_DT, 'YYYY-MM-DD HH:MM') AS APPROVED_DT ,CU_APP.USER_NM AS APPROVER_NM ,CAD.TARGET_TP_CD ,CASE WHEN CAD.TARGET_TP_CD = 'MOBIGEN' THEN '모비젠' WHEN CAD.TARGET_TP_CD = 'KWARE' THEN '케이웨어' END AS TARGET_TP_CD_NM ,( SELECT COALESCE(ROUND(SUM(CDM.RATINGS) / COUNT(*)), 0) FROM CETUS_DATASET_COMMENT CDM WHERE CDM.APPROVED_DATASET_UID = CAD.UID ) AS RATINGS ,CASE WHEN CDB.APPROVED_DATASET_UID IS NOT NULL THEN 'Y' ELSE 'N' END AS BOOKMARK_YN ,CAD.DELETE_AT FROM CETUS_APPROVED_DATASET CAD -- 진열관리 중인 데이터셋 LEFT JOIN CETUS_DATASET_UI CDU ON CDU.APPROVED_DATASET_UID = CAD.UID -- 진열관리 중인 데이터셋의 UI LEFT JOIN CETUS_USER CU_APP ON CU_APP.UID = CAD.APPROVER_UID -- 모비젠의 데이터셋을 진열등록한 유저 LEFT JOIN CETUS_DATASET_MAIN_UI CDMU ON CDMU.UID = CDU.MAIN_UI_UID -- KWARE 포탈 시스템의 메인 UI LEFT JOIN CETUS_DATASET_CATEGORY CDC ON CDC.UID = CDU.CATEGORY_UID -- 진열관리 중인 데이터셋의 카테고리 LEFT JOIN CETUS_DATASET_BOOKMARK CDB ON CDB.APPROVED_DATASET_UID = CAD.UID AND CDB.USER_UID = #{userUid} -- 진열관리 중인 데이터셋에 대해 로그인 사용자의 북마크 여부 WHERE CAD.WORKPLACE_UID = #{workplaceUid} AND CAD.DELETE_AT = 'N'
AND CDU.SHOW_AT = #{showAt}
AND CDMU.TYPE_CD = #{uiTypeCd}
AND CAD.TARGET_TP_CD = #{dataTarType}
AND CAD.APPROVED_DT >= #{startDate}::TIMESTAMP /* 종료일에 1일을 더한 날의 '00:00:00' 미만으로 설정하여 해당 날짜 전체 포함 */ AND CAD.APPROVED_DT > (#{endDate}::DATE + INTERVAL '1 day')
AND CDC.UID IN
#{categoryUid}
ORDER BY CAD.APPROVED_DT DESC
OFFSET ${startNumber} LIMIT ${endNumber}

/* cetusApprovedDataset.getDatasetPageCount */
SELECT COUNT(*)
  FROM CETUS_APPROVED_DATASET CAD -- 진열관리 중인 데이터셋
  LEFT JOIN CETUS_DATASET_UI CDU ON CDU.APPROVED_DATASET_UID = CAD.UID -- 진열관리 중인 데이터셋의 UI
  LEFT JOIN CETUS_USER CU_APP ON CU_APP.UID = CAD.APPROVER_UID -- 모비젠의 데이터셋을 진열등록한 유저
  LEFT JOIN CETUS_DATASET_MAIN_UI CDMU ON CDMU.UID = CDU.MAIN_UI_UID -- KWARE 포탈 시스템의 메인 UI
  LEFT JOIN CETUS_DATASET_CATEGORY CDC ON CDC.UID = CDU.CATEGORY_UID -- 진열관리 중인 데이터셋의 카테고리
  LEFT JOIN CETUS_DATASET_BOOKMARK CDB ON CDB.APPROVED_DATASET_UID = CAD.UID AND CDB.USER_UID = #{userUid} -- 진열관리 중인 데이터셋에 대해 로그인 사용자의 북마크 여부
 WHERE CAD.WORKPLACE_UID = #{workplaceUid}
   AND CAD.DELETE_AT = 'N'

   AND CDU.SHOW_AT = #{showAt}


   AND CDMU.TYPE_CD = #{uiTypeCd}


   AND CAD.TARGET_TP_CD = #{dataTarType}


    AND CAD.APPROVED_DT >= #{startDate}::TIMESTAMP
    /* 종료일에 1일을 더한 날의 '00:00:00' 미만으로 설정하여 해당 날짜 전체 포함 */
    AND CAD.APPROVED_DT > (#{endDate}::DATE + INTERVAL '1 day')


   AND CDC.UID IN

       #{categoryUid}

/* cetusApprovedDataset.getApprovedMetadataIdList */
SELECT EXISTS (
    SELECT 1
      FROM CETUS_APPROVED_DATASET
     WHERE DELETE_AT = 'N'
       AND WORKPLACE_UID = #{workplaceUid}
       AND METADATA_ID = #{metadataId}
)

