/* cetusApprovedDataset.insert */
INSERT INTO CETUS_APPROVED_DATASET (
     METADATA_ID
    ,WORKPLACE_UID
    ,APPROVED_DT
    ,APPROVER_UID
    ,TARGET_TP_CD
    ,DELETE_AT
) VALUES (
     #{metadataId}
    ,#{workplaceUid}
    ,NOW()
    ,#{approverUid}
    ,#{targetTpCd}
    ,'N'
)

