/* cetusApprovedDataset.getHomeDatasetList */ SELECT CAD.UID AS APPROVED_UID ,CAD.METADATA_ID ,TO_CHAR(CAD.APPROVED_DT, 'YYYY-MM-DD HH:MM') AS APPROVED_DT ,CU_APP.USER_NM AS APPROVER_NM ,CAD.TARGET_TP_CD ,CASE WHEN CAD.TARGET_TP_CD = 'MOBIGEN' THEN '모비젠' WHEN CAD.TARGET_TP_CD = 'KWARE' THEN '케이웨어' END AS TARGET_TP_CD_NM ,( SELECT COALESCE(ROUND(SUM(CDM.RATINGS) / COUNT(*)), 0) FROM CETUS_DATASET_COMMENT CDM WHERE CDM.APPROVED_DATASET_UID = CAD.UID ) AS RATINGS ,CASE WHEN CDB.APPROVED_DATASET_UID IS NOT NULL THEN 'Y' ELSE 'N' END AS BOOKMARK_YN ,CAD.DELETE_AT FROM CETUS_APPROVED_DATASET CAD -- 진열관리 중인 데이터셋 INNER JOIN CETUS_DATASET_UI CDU ON CAD.UID = CDU.APPROVED_DATASET_UID -- 진열관리 중인 데이터셋의 UI LEFT JOIN CETUS_USER CU_APP ON CU_APP.UID = CAD.APPROVER_UID -- 모비젠의 데이터셋을 진열등록한 유저 LEFT JOIN CETUS_DATASET_CATEGORY CDC ON CDC.UID = CDU.CATEGORY_UID -- 진열관리 중인 데이터셋의 카테고리 LEFT JOIN CETUS_FILE CF ON CF.FILE_UID = CDU.THUMB_UID AND CF.USE_AT = 'Y' -- 진열관리 중인 데이터셋의 썸네일 이미지 LEFT JOIN CETUS_DATASET_BOOKMARK CDB ON CDB.APPROVED_DATASET_UID = CAD.UID AND CDB.USER_UID = #{userUid} -- 진열관리 중인 데이터셋에 대해 로그인 사용자의 북마크 여부 WHERE CAD.WORKPLACE_UID = #{workplaceUid} AND CDU.MAIN_UI_UID = #{mainUiUid}
AND CDU.CATEGORY_UID = #{selectedCategory}
AND CAD.DELETE_AT = 'N' AND CDU.SHOW_AT = 'Y' ORDER BY CDU.SORT_NO LIMIT #{limitCount}

mapper.update:
/* cetusApprovedDataset.updateApprovedDatasetSearchData */
UPDATE CETUS_APPROVED_DATASET
   SET SEARCH_DATA = #{searchData}::jsonb
 WHERE METADATA_ID = #{metadataId}
